function SAP:GetWeakAura(name)
    if name == "anchor_weakaura" then
        return WeakAura_Imports.anchor_weakaura
    elseif name == "interrupt_weakaura" then
        return WeakAura_Imports.interrupt_weakaura
    elseif name == "raid_weakaura" then
        return WeakAura_Imports.raid_weakaura
    end
end
